def count_letters(text):
    """
    Count the frequency of each letter in the given text.

    Parameters:
    text (str): The input string to analyze.

    Returns:
    dict: A dictionary with letters as keys and their frequencies as values.
    """
    letter_counts = {}
    for char in text:
